content:
{
  "sentences": [
    {
      "text": "這件上衣的顏色太亮了，我不喜歡。",
      "pinyin": "Zhè jiàn shàngyī de yánsè tài liàng le, wǒ bù xǐhuān.",
      "pinyin_numeric": "zhe4 jian4 shang4yi1 de0 yan2se4 tai4 liang4 le0, wo3 bu4 xi3huan1.",
      "translation_en": "The color of this top is too bright; I don't like it.",
      "translation_ko": "이 상의의 색상이 너무 밝아서 마음에 안 들어요."
    },
    {
      "text": "這條褲子太長了，有沒有短一點的？",
      "pinyin": "Zhè tiáo kùzi tài cháng le, yǒu méiyǒu duǎn yīdiǎn de?",
      "pinyin_numeric": "zhe4 tiao2 ku4zi0 tai4 chang2 le0, you3 mei2you3 duan3 yi1dian3 de0?",
      "translation_en": "These pants are too long; do you have a shorter pair?",
      "translation_ko": "이 바지는 너무 길어요, 더 짧은 게 있나요?"
    },
    {
      "text": "這雙鞋子太貴了，可以打折嗎？",
      "pinyin": "Zhè shuāng xiézi tài guì le, kěyǐ dǎzhé ma?",
      "pinyin_numeric": "zhe4 shuang1 xie2zi0 tai4 gui4 le0, ke3yi3 da3zhe2 ma0?",
      "translation_en": "These shoes are too expensive; can you give a discount?",
      "translation_ko": "이 신발은 너무 비싸요, 할인해 주실 수 있나요?"
    },
    {
      "text": "這件外套的尺寸太小了，有大號的嗎？",
      "pinyin": "Zhè jiàn wàitào de chǐcùn tài xiǎo le, yǒu dàhào de ma?",
      "pinyin_numeric": "zhe4 jian4 wai4tao4 de0 chi3cun4 tai4 xiao3 le0, you3 da4hao4 de0 ma0?",
      "translation_en": "The size of this jacket is too small; do you have a large?",
      "translation_ko": "이 외투의 사이즈가 너무 작아요, 큰 사이즈 있나요?"
    },
    {
      "text": "這條裙子太短了，有沒有長一點的？",
      "pinyin": "Zhè tiáo qúnzi tài duǎn le, yǒu méiyǒu cháng yīdiǎn de?",
      "pinyin_numeric": "zhe4 tiao2 qun2zi0 tai4 duan3 le0, you3 mei2you3 chang2 yi1dian3 de0?",
      "translation_en": "This skirt is too short; do you have a longer one?",
      "translation_ko": "이 치마는 너무 짧아요, 더 긴 게 있나요?"
    },
    {
      "text": "這件上衣的材質太厚了，夏天穿會很熱。",
      "pinyin": "Zhè jiàn shàngyī de cáizhí tài hòu le, xiàtiān chuān huì hěn rè.",
      "pinyin_numeric": "zhe4 jian4 shang4yi1 de0 cai2zhi2 tai4 hou4 le0, xia4tian1 chuan1 hui4 hen3 re4.",
      "translation_en": "The material of this top is too thick; it will be hot to wear in summer.",
      "translation_ko": "이 상의의 소재가 너무 두꺼워서 여름에 입으면 더울 거예요."
    },
    {
      "text": "這雙襪子的顏色太暗了，有亮一點的嗎？",
      "pinyin": "Zhè shuāng wàzi de yánsè tài àn le, yǒu liàng yīdiǎn de ma?",
      "pinyin_numeric": "zhe4 shuang1 wa4zi0 de0 yan2se4 tai4 an4 le0, you3 liang4 yi1dian3 de0 ma0?",
      "translation_en": "The color of these socks is too dark; do you have a brighter one?",
      "translation_ko": "이 양말의 색상이 너무 어두워요, 더 밝은 게 있나요?"
    },
    {
      "text": "這頂帽子太大了，有沒有小一點的？",
      "pinyin": "Zhè dǐng màozi tài dà le, yǒu méiyǒu xiǎo yīdiǎn de?",
      "pinyin_numeric": "zhe4 ding3 mao4zi0 tai4 da4 le0, you3 mei2you3 xiao3 yi1dian3 de0?",
      "translation_en": "This hat is too big; do you have a smaller one?",
      "translation_ko": "이 모자는 너무 커요, 더 작은 게 있나요?"
    },
    {
      "text": "這件外套的顏色太普通了，有沒有特別一點的？",
      "pinyin": "Zhè jiàn wàitào de yánsè tài pǔtōng le, yǒu méiyǒu tèbié yīdiǎn de?",
      "pinyin_numeric": "zhe4 jian4 wai4tao4 de0 yan2se4 tai4 pu3tong1 le0, you3 mei2you3 te4bie2 yi1dian3 de0?",
      "translation_en": "The color of this jacket is too ordinary; do you have something more special?",
      "translation_ko": "이 외투의 색상이 너무 평범해요, 더 특별한 게 있나요?"
    },
    {
      "text": "這條褲子的尺寸太大了，我穿不合身。",
      "pinyin": "Zhè tiáo kùzi de chǐcùn tài dà le, wǒ chuān bù héshēn.",
      "pinyin_numeric": "zhe4 tiao2 ku4zi0 de0 chi3cun4 tai4 da4 le0, wo3 chuan1 bu4 he2shen1.",
      "translation_en": "The size of these pants is too big; they don't fit me.",
      "translation_ko": "이 바지의 사이즈가 너무 커서 제게 맞지 않아요."
    }
  ]
}
